import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

// Pages Import (खात्री कर की या फाईल्स pages फोल्डरमध्ये आहेत)
import Home from './pages/Home';
import Login from './pages/Login'; 
import Signup from './pages/Signup'; 
import Dashboard from './pages/Dashboard';
import Marketplace from './pages/Marketplace'; 

// नवीन पेजेस इम्पॉर्ट केले (हे तू विसरली होतीस)
import About from './pages/About'; 
import Contact from './pages/Contact';

// Components Import
import Navbar from './components/Navbar'; 
import Footer from './components/Footer'; 
import './App.css';

function App() {
  return (
    <Router>
      {/* १. नेवबार नेहमी Routes च्या बाहेर हवा */}
      <Navbar />

      <div className="main-content-wrapper" style={{ 
        minHeight: 'calc(100vh - 150px)', 
        paddingTop: '20px', 
        paddingBottom: '40px',
        backgroundColor: '#f8fafc' 
      }}>
        <div className="container">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/signup" element={<Signup />} />
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/marketplace" element={<Marketplace />} />
            
            {/* २. आता हे Routes व्यवस्थित चालतील */}
            <Route path="/about" element={<About />} />
            <Route path="/contact" element={<Contact />} />
            
            {/* ३. चुकीची URL टाकल्यास Home वर नेण्यासाठी */}
            <Route path="*" element={<Home />} />
          </Routes>
        </div>
      </div>

      <Footer />
    </Router>
  );
}

export default App;
